                    <div className="flex flex-col items-center"><span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Total Dist</span><span className="text-xl font-black text-blue-600">{analytics.totalDist} <span className="text-xs">km</span></span></div>
